#define GMP_FOR_EACH(call, ...) \
    GMP_EXPAND( GMP_OVERLOAD_INVOKE(_GMP_FOR_EACH, GMP_SIZE_OF_VAARGS(__VA_ARGS__))(call, __VA_ARGS__) )
